import java.io.IOException;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSafeServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Encode user input to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedInput = encoder.encodeForHTML(userInput);

        // Safe HTML response with properly encoded user input
        String htmlResponse = "<html><body><p>User Input: " + encodedInput + "</p></body></html>";

        response.setContentType("text/html");
        response.getWriter().println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
